// components/TourFilters.jsx
import { useState, useRef, useEffect } from 'react';
import { useTourFilters } from '../hooks/useTourFilters';
import CustomTooltip from './CustomTooltip';

const cities = ['Москва', 'СПб', 'Казань', 'Екатеринбург', 'Новосибирск'];
const countries = ['Турция', 'Египет', 'ОАЭ', 'Таиланд', 'Россия'];

function TourFilters() {
  const { adults, selectedChildren, /* ... остальные */ } = useTourFilters();
  const [tooltip, setTooltip] = useState({ visible: false, type: '', position: {x:0,y:0} });
  const filtersRef = useRef(null);

  // Обработчик кликов по триггерам
  const handleFilterClick = (e, type) => {
    setTooltip({
      visible: true,
      type,
      position: { x: e.pageX, y: e.pageY }
    });
  };

  // Закрытие tooltip
  useEffect(() => {
    const handleClickOutside = (e) => {
      if (filtersRef.current && !filtersRef.current.contains(e.target)) {
        setTooltip(prev => ({...prev, visible: false}));
      }
    };
    document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, []);

  const renderTouristsUI = () => (
    <div>
      <div className="adults-counter">
        <button onClick={() => updateAdults(-1)}>-</button>
        <span>{adults} взрослых</span>
        <button onClick={() => updateAdults(1)}>+</button>
      </div>
      <div className="children-list">
        {selectedChildren.map((age, idx) => (
          <div key={idx} className="child-item">
            Ребенок {idx+1} ({age})
            <button onClick={() => removeChild(idx)}>×</button>
          </div>
        ))}
      </div>
      <button onClick={() => {/* show age selector */}}>
        + Добавить ребенка
      </button>
      <button onClick={() => {
        // Применить
        setTooltip(prev => ({...prev, visible: false}));
      }}>Применить</button>
    </div>
  );

  const renderCities = () => (
    <div>
      {cities.map(city => (
        <div key={city} onClick={() => {/* выбрать */}}>
          {city}
        </div>
      ))}
    </div>
  );

  return (
    <div className="tour-filters" ref={filtersRef}>
      {/* Триггеры */}
      <div className="TVTouristsFilter" onClick={(e) => handleFilterClick(e, 'tourists')}>
        <div className="TVMainSelectContent">2 взрослых</div>
      </div>
      
      <div className="TVDepartureFilter" onClick={(e) => handleFilterClick(e, 'city')}>
        <div className="TVMainSelectContent">Москва</div>
      </div>

      {/* Tooltip */}
      <CustomTooltip 
        visible={tooltip.visible}
        position={tooltip.position}
        title={tooltip.type === 'tourists' ? 'Туристы' : 'Выбор'}
      >
        {tooltip.type === 'tourists' && renderTouristsUI()}
        {tooltip.type === 'city' && renderCities()}
        {/* Аналогично для дат, ночей */}
      </CustomTooltip>
    </div>
  );
}

export default TourFilters;
